import React, {useState, useEffect} from 'react';

import classes from './input-area.module.css';

import getText from '../../services/get-text';

const InputArea = () => {
    const [inputValue, setInputValue] = useState('');

    useEffect(() => {
        const identifier = setTimeout(() => {
            console.log(inputValue);
        }, 500);

        return () => {
            clearTimeout(identifier);
        };

    }, [inputValue]);

    const inputChangeHandler = (event) => {
        setInputValue(event.target.value);
    };

    const onSubmitHandler = (event) => {
        event.preventDefault();
        console.log(getText(inputValue).text);
        setInputValue('');
    };

    return (
        <form className={classes['input-area']} onSubmit={onSubmitHandler}>
            <input type='text' value={inputValue} onChange={inputChangeHandler}/>
            <div className={classes['input-area-markup']}></div>
            <button></button>
        </form>
    );
};

export default InputArea;